contracts/MockERC20.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title MockERC20
 * @dev Simple ERC-20 token for testing payments in the Task Marketplace
 */
contract MockERC20 is ERC20, Ownable {
    uint8 private constant DECIMALS = 18;

    constructor() ERC20("TaskToken", "TT") Ownable(msg.sender) {
        // Mint 1,000,000 tokens to deployer for testing
        _mint(msg.sender, 1000000 * 10 ** DECIMALS);
    }

    /**
     * @dev Mint tokens (owner only) - for testing
     * @param to Recipient address
     * @param amount Amount to mint
     */
    function mint(address to, uint256 amount) external onlyOwner {
        _mint(to, amount);
    }

    /**
     * @dev Get token decimals
     */
    function decimals() public pure override returns (uint8) {
        return DECIMALS;
    }
}

contracts/TaskEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title TaskEscrow
 * @dev Decentralized escrow contract for AI Agent Task Marketplace
 * @notice This contract manages task creation, bidding, and payment distribution
 */
contract TaskEscrow is ReentrancyGuard, Ownable {
    using SafeERC20 for IERC20;

    // ============ Enums ============

    enum TaskStatus {
        Open,           // Task is open for bidding
        InProgress,     // Task assigned to an agent
        Completed,      // Task completed, awaiting approval
        Disputed,       // Task is under dispute
        Cancelled,      // Task was cancelled
        Finalized       // Payment released, task closed
    }

    enum BidStatus {
        Pending,        // Bid submitted, awaiting response
        Accepted,       // Bid accepted by task creator
        Rejected,       // Bid rejected by task creator
        Withdrawn       // Bid withdrawn by agent
    }

    // ============ Structs ============

    struct Task {
        uint256 id;
        address creator;
        address assignedAgent;
        uint256 reward;
        uint256 deadline;
        TaskStatus status;
        string title;
        string description;
        string resultHash;      // IPFS hash or similar for task results
        uint256 createdAt;
        uint256 completedAt;
    }

    struct Bid {
        uint256 id;
        uint256 taskId;
        address agent;
        uint256 amount;
        BidStatus status;
        string message;         // Agent's proposal message
        uint256 createdAt;
    }

    // ============ State Variables ============

    IERC20 public immutable paymentToken;

    uint256 public taskCounter;
    uint256 public bidCounter;

    // Task ID => Task
    mapping(uint256 => Task) public tasks;

    // Task ID => Bid IDs
    mapping(uint256 => uint256[]) public taskBids;

    // Bid ID => Bid
    mapping(uint256 => Bid) public bids;

    // User address => Task IDs (as creator)
    mapping(address => uint256[]) public creatorTasks;

    // User address => Task IDs (as agent)
    mapping(address => uint256[]) public agentTasks;

    // Task ID => deposited amount
    mapping(uint256 => uint256) public deposits;

    // ============ Events ============

    event TaskCreated(
        uint256 indexed taskId,
        address indexed creator,
        uint256 reward,
        string title,
        uint256 deadline
    );

    event TaskUpdated(
        uint256 indexed taskId,
        TaskStatus newStatus
    );

    event BidSubmitted(
        uint256 indexed bidId,
        uint256 indexed taskId,
        address indexed agent,
        uint256 amount,
        string message
    );

    event BidStatusChanged(
        uint256 indexed bidId,
        uint256 indexed taskId,
        BidStatus newStatus
    );

    event DepositMade(
        uint256 indexed taskId,
        address indexed depositor,
        uint256 amount
    );

    event PaymentReleased(
        uint256 indexed taskId,
        address indexed agent,
        uint256 amount
    );

    event TaskCancelled(
        uint256 indexed taskId,
        address indexed creator,
        uint256 refundAmount
    );

    event DisputeRaised(
        uint256 indexed taskId,
        address indexed raisedBy
    );

    event DisputeResolved(
        uint256 indexed taskId,
        address winner,
        uint256 amount
    );

    // ============ Modifiers ============

    modifier onlyTaskCreator(uint256 _taskId) {
        require(tasks[_taskId].creator == msg.sender, "Not task creator");
        _;
    }

    modifier onlyAssignedAgent(uint256 _taskId) {
        require(tasks[_taskId].assignedAgent == msg.sender, "Not assigned agent");
        _;
    }

    modifier taskExists(uint256 _taskId) {
        require(_taskId > 0 && _taskId <= taskCounter, "Task does not exist");
        _;
    }

    modifier taskInStatus(uint256 _taskId, TaskStatus _status) {
        require(tasks[_taskId].status == _status, "Invalid task status");
        _;
    }

    // ============ Constructor ============

    constructor(address _paymentToken) Ownable(msg.sender) {
        require(_paymentToken != address(0), "Invalid token address");
        paymentToken = IERC20(_paymentToken);
    }

    // ============ External Functions ============

    /**
     * @dev Create a new task
     * @param _title Task title
     * @param _description Task description
     * @param _reward Reward amount in token units
     * @param _deadline Deadline timestamp
     */
    function createTask(
        string calldata _title,
        string calldata _description,
        uint256 _reward,
        uint256 _deadline
    ) external returns (uint256) {
        require(bytes(_title).length > 0, "Title required");
        require(_reward > 0, "Reward must be positive");
        require(_deadline > block.timestamp, "Deadline must be in future");

        taskCounter++;

        Task storage newTask = tasks[taskCounter];
        newTask.id = taskCounter;
        newTask.creator = msg.sender;
        newTask.reward = _reward;
        newTask.deadline = _deadline;
        newTask.status = TaskStatus.Open;
        newTask.title = _title;
        newTask.description = _description;
        newTask.createdAt = block.timestamp;

        creatorTasks[msg.sender].push(taskCounter);

        emit TaskCreated(taskCounter, msg.sender, _reward, _title, _deadline);

        return taskCounter;
    }

    /**
     * @dev Deposit tokens as escrow for a task
     * @param _taskId Task ID
     * @param _amount Amount to deposit
     */
    function depositEscrow(uint256 _taskId, uint256 _amount)
        external
        nonReentrant
        taskExists(_taskId)
        taskInStatus(_taskId, TaskStatus.Open)
    {
        require(_amount > 0, "Amount must be positive");

        Task storage task = tasks[_taskId];
        require(task.creator == msg.sender, "Not task creator");

        deposits[_taskId] += _amount;

        paymentToken.safeTransferFrom(msg.sender, address(this), _amount);

        emit DepositMade(_taskId, msg.sender, _amount);
    }

    /**
     * @dev Submit a bid for a task
     * @param _taskId Task ID
     * @param _amount Proposed amount
     * @param _message Proposal message
     */
    function submitBid(
        uint256 _taskId,
        uint256 _amount,
        string calldata _message
    ) 
        external
        taskExists(_taskId)
        taskInStatus(_taskId, TaskStatus.Open)
        returns (uint256)
    {
        require(_amount > 0, "Amount must be positive");
        require(tasks[_taskId].creator != msg.sender, "Creator cannot bid");

        bidCounter++;

        Bid storage newBid = bids[bidCounter];
        newBid.id = bidCounter;
        newBid.taskId = _taskId;
        newBid.agent = msg.sender;
        newBid.amount = _amount;
        newBid.status = BidStatus.Pending;
        newBid.message = _message;
        newBid.createdAt = block.timestamp;

        taskBids[_taskId].push(bidCounter);

        emit BidSubmitted(bidCounter, _taskId, msg.sender, _amount, _message);

        return bidCounter;
    }

    /**
     * @dev Accept a bid and assign the task
     * @param _bidId Bid ID to accept
     */
    function acceptBid(uint256 _bidId)
        external
        nonReentrant
    {
        Bid storage bid = bids[_bidId];
        require(bid.id == _bidId, "Bid does not exist");
        require(bid.status == BidStatus.Pending, "Bid not pending");

        Task storage task = tasks[bid.taskId];
        require(task.creator == msg.sender, "Not task creator");
        require(task.status == TaskStatus.Open, "Task not open");
        require(deposits[bid.taskId] >= bid.amount, "Insufficient escrow");

        // Update bid status
        bid.status = BidStatus.Accepted;

        // Update task
        task.assignedAgent = bid.agent;
        task.reward = bid.amount;
        task.status = TaskStatus.InProgress;

        // Reject other pending bids
        uint256[] storage bidIds = taskBids[bid.taskId];
        for (uint256 i = 0; i < bidIds.length; i++) {
            if (bidIds[i] != _bidId && bids[bidIds[i]].status == BidStatus.Pending) {
                bids[bidIds[i]].status = BidStatus.Rejected;
                emit BidStatusChanged(bidIds[i], bid.taskId, BidStatus.Rejected);
            }
        }

        agentTasks[bid.agent].push(bid.taskId);

        emit BidStatusChanged(_bidId, bid.taskId, BidStatus.Accepted);
        emit TaskUpdated(bid.taskId, TaskStatus.InProgress);
    }

    /**
     * @dev Reject a bid
     * @param _bidId Bid ID to reject
     */
    function rejectBid(uint256 _bidId) external {
        Bid storage bid = bids[_bidId];
        require(bid.id == _bidId, "Bid does not exist");
        require(bid.status == BidStatus.Pending, "Bid not pending");

        Task storage task = tasks[bid.taskId];
        require(task.creator == msg.sender, "Not task creator");

        bid.status = BidStatus.Rejected;

        emit BidStatusChanged(_bidId, bid.taskId, BidStatus.Rejected);
    }

    /**
     * @dev Withdraw a bid (by agent)
     * @param _bidId Bid ID to withdraw
     */
    function withdrawBid(uint256 _bidId) external {
        Bid storage bid = bids[_bidId];
        require(bid.id == _bidId, "Bid does not exist");
        require(bid.status == BidStatus.Pending, "Bid not pending");
        require(bid.agent == msg.sender, "Not bid owner");

        bid.status = BidStatus.Withdrawn;

        emit BidStatusChanged(_bidId, bid.taskId, BidStatus.Withdrawn);
    }

    /**
     * @dev Mark task as completed (by agent)
     * @param _taskId Task ID
     * @param _resultHash IPFS hash or reference to task results
     */
    function completeTask(uint256 _taskId, string calldata _resultHash)
        external
        onlyAssignedAgent(_taskId)
        taskInStatus(_taskId, TaskStatus.InProgress)
    {
        Task storage task = tasks[_taskId];

        task.status = TaskStatus.Completed;
        task.resultHash = _resultHash;
        task.completedAt = block.timestamp;

        emit TaskUpdated(_taskId, TaskStatus.Completed);
    }

    /**
     * @dev Approve completed task and release payment
     * @param _taskId Task ID
     */
    function approveAndRelease(uint256 _taskId)
        external
        nonReentrant
        onlyTaskCreator(_taskId)
        taskInStatus(_taskId, TaskStatus.Completed)
    {
        Task storage task = tasks[_taskId];
        uint256 paymentAmount = deposits[_taskId];

        require(paymentAmount >= task.reward, "Insufficient deposit");
        require(task.assignedAgent != address(0), "No agent assigned");

        // Update state before transfer
        deposits[_taskId] = 0;
        task.status = TaskStatus.Finalized;

        // Transfer payment to agent
        paymentToken.safeTransfer(task.assignedAgent, task.reward);

        // Refund excess to creator
        if (paymentAmount > task.reward) {
            paymentToken.safeTransfer(task.creator, paymentAmount - task.reward);
        }

        emit PaymentReleased(_taskId, task.assignedAgent, task.reward);
        emit TaskUpdated(_taskId, TaskStatus.Finalized);
    }

    /**
     * @dev Raise a dispute
     * @param _taskId Task ID
     */
    function raiseDispute(uint256 _taskId)
        external
        taskExists(_taskId)
    {
        Task storage task = tasks[_taskId];
        require(
            msg.sender == task.creator || msg.sender == task.assignedAgent,
            "Not authorized"
        );
        require(
            task.status == TaskStatus.InProgress || task.status == TaskStatus.Completed,
            "Invalid status for dispute"
        );

        task.status = TaskStatus.Disputed;

        emit DisputeRaised(_taskId, msg.sender);
        emit TaskUpdated(_taskId, TaskStatus.Disputed);
    }

    /**
     * @dev Resolve dispute (owner only)
     * @param _taskId Task ID
     * @param _winner Address of the dispute winner
     * @param _creatorPercent Percentage to creator (0-100)
     */
    function resolveDispute(
        uint256 _taskId,
        address _winner,
        uint8 _creatorPercent
    )
        external
        nonReentrant
        onlyOwner
        taskInStatus(_taskId, TaskStatus.Disputed)
    {
        require(_creatorPercent <= 100, "Invalid percentage");

        Task storage task = tasks[_taskId];
        uint256 totalDeposit = deposits[_taskId];

        deposits[_taskId] = 0;
        task.status = TaskStatus.Finalized;

        uint256 creatorAmount = (totalDeposit * _creatorPercent) / 100;
        uint256 agentAmount = totalDeposit - creatorAmount;

        if (creatorAmount > 0) {
            paymentToken.safeTransfer(task.creator, creatorAmount);
        }
        if (agentAmount > 0 && task.assignedAgent != address(0)) {
            paymentToken.safeTransfer(task.assignedAgent, agentAmount);
        }

        emit DisputeResolved(_taskId, _winner, totalDeposit);
        emit TaskUpdated(_taskId, TaskStatus.Finalized);
    }

    /**
     * @dev Cancel an open task
     * @param _taskId Task ID
     */
    function cancelTask(uint256 _taskId)
        external
        nonReentrant
        onlyTaskCreator(_taskId)
    {
        Task storage task = tasks[_taskId];
        require(
            task.status == TaskStatus.Open || task.status == TaskStatus.InProgress,
            "Cannot cancel"
        );

        uint256 refundAmount = deposits[_taskId];
        deposits[_taskId] = 0;
        task.status = TaskStatus.Cancelled;

        // Refund deposit
        if (refundAmount > 0) {
            paymentToken.safeTransfer(task.creator, refundAmount);
        }

        emit TaskCancelled(_taskId, msg.sender, refundAmount);
        emit TaskUpdated(_taskId, TaskStatus.Cancelled);
    }

    // ============ View Functions ============

    /**
     * @dev Get task details
     */
    function getTask(uint256 _taskId)
        external
        view
        taskExists(_taskId)
        returns (Task memory)
    {
        return tasks[_taskId];
    }

    /**
     * @dev Get all bids for a task
     */
    function getTaskBids(uint256 _taskId)
        external
        view
        taskExists(_taskId)
        returns (Bid[] memory)
    {
        uint256[] storage bidIds = taskBids[_taskId];
        Bid[] memory taskBidList = new Bid[](bidIds.length);

        for (uint256 i = 0; i < bidIds.length; i++) {
            taskBidList[i] = bids[bidIds[i]];
        }

        return taskBidList;
    }

    /**
     * @dev Get tasks created by a user
     */
    function getCreatorTasks(address _creator)
        external
        view
        returns (uint256[] memory)
    {
        return creatorTasks[_creator];
    }

    /**
     * @dev Get tasks assigned to an agent
     */
    function getAgentTasks(address _agent)
        external
        view
        returns (uint256[] memory)
    {
        return agentTasks[_agent];
    }

    /**
     * @dev Get bid details
     */
    function getBid(uint256 _bidId)
        external
        view
        returns (Bid memory)
    {
        return bids[_bidId];
    }
}

